def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 2:
            penalty = 0
            for k in range(1, 6):
                penalty += (ratio ** (2 * k)) / (k ** 2 + 1)
            priorities[i] = (ratio ** 4) + penalty * np.log1p(ratio)
        elif 1 < ratio <= 2:
            score = 0
            for j in range(1, 8):
                sign = (-1) ** (j + 1)
                term = sign * (ratio ** (j+1)) / (j + 2)
                score += term
            multiplier = 20 if ratio < 1.3 else 12 if ratio < 1.7 else 7
            priorities[i] = abs(score) * multiplier
            if 1.8 < ratio < 2:
                extra = 0
                for m in range(1, 5):
                    extra += (ratio ** (m/2)) / (m + 0.5)
                priorities[i] += extra
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 10):
                sign = 1 if j % 3 == 0 else -1
                term = sign * (ratio ** j) / (j + 1)
                score += term
            multiplier = 25 if ratio < 0.2 else 15 if ratio < 0.5 else 8
            priorities[i] = abs(score) * multiplier
            if ratio > 0.75:
                extra = 0
                for m in range(1, 6):
                    extra += ((-1) ** m) * (ratio ** m) / (m + 2)
                priorities[i] += abs(extra)
        else:
            if item == 0:
                priorities[i] = 0
            else:
                fallback = 0
                for p in range(1, 5):
                    for q in range(1, 4):
                        fallback += ((-1) ** (p+q)) * np.exp(-p*q*ratio)
                priorities[i] = fallback if fallback > 0 else np.inf
    return priorities
